import{_ as a,o as t,c as n,j as e,a as o,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"和平使者柯尔特","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/和平使者柯尔特.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/和平使者柯尔特.md"}'),p={name:"4.资源分区/7.物品与装备/2.武器/远程武器/6.可升级/和平使者柯尔特.md"};function l(d,r,_,b,i,h){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"和平使者柯尔特",tabindex:"-1"},[o("和平使者柯尔特 "),e("a",{class:"header-anchor",href:"#和平使者柯尔特","aria-label":'Permalink to "和平使者柯尔特"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序000")])])],-1),s('<h1 id="和平使者柯尔特-1" tabindex="-1">和平使者柯尔特 <a class="header-anchor" href="#和平使者柯尔特-1" aria-label="Permalink to &quot;和平使者柯尔特&quot;">​</a></h1><p>和平使者柯尔特<br> “上帝创造人类，柯尔特创造平等，而我带来和平”<br> D+500<br> 特异本质<br> 这是一柄老旧的大型左轮手枪，紫褐色木制手柄，银灰色枪身，其枪管上刻着一行字：此地无我，亦无枪火。<br> 武器伤害7 高速5 基础装弹量6 射程30米</p><p>【Clover】-幸运女神总是为我展颜微笑<br> 在一次不附带任何射技的射击前，可以以一个迅捷动作向幸运女神祈祷。在射击时掷一枚D6，若所出数字为6，则那颗子弹将在女神的指引下射出，在最完美的路径上经过并击中敌人。只要那次攻击成功命中且造成了伤害，则这次攻击造成的伤害会提升一半</p><p>【Thyme】-人总是需要一些勇气<br> 和平使者柯尔特无法进行瞄准，也不会因无法瞄准而获得其他收益（如快枪手），除非支付1XP以解除这个限制。当和平使者柯尔特进行对特殊部位攻击时，对方获得闪避加值和你受到的特殊部位减值均翻倍。若如此做，且你的攻击成功命中且造成了伤害，则你持续获得其真实视野直至那个场景结束，当其离开你的视野范围或敏感范围取低时，便会丢失对其的真实视野</p><p>C+1000<br> 武器伤害提升至15L<br> 【Dollars】-年轻人…你从此富有了<br> 在一场影片开始前，都可以在主神处以1500点奖励点的价格购买一张悬赏令，在那场影片中，主神将可以选择一名难度至少高购买者1级的敌人设置为悬赏对象，若悬赏对象成功被其杀死，则那张悬赏令将被收回，并在那场影片结束时为其提供一个额外的D级支线</p><p>【Cheyenne】-出去，你不会见证我的死亡<br> 现在，【Clover】将可以在任何射技上展现，且无需再使用迅捷动作以祈祷，但在一次射击前仍只能进行一次祈祷</p><p>B+2000<br> 武器伤害提升至22L<br> 【Kane】-你们留着它吧<br> 现在你在使用【Thyme】的效果进行一次攻击时，将无需再承受额外的减值，若成功命中且造成了伤害，则其还会陷入重伤状态中，持续一个场景</p><p>【Parsley】-回去告诉你妈妈吧，山谷里再不会有枪声了<br> 一日一次，只有当此刻的时间为正午或午夜时才能如此做。在进行一次射击前发动，这次攻击的伤害出目将翻倍。若此次射击成功触发了【Clover】，则还会额外附带A级心灵来源的惊惧效果，使用意志豁免进行对抗。这个效果将持续一轮</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(p,[["render",l]]);export{f as __pageData,m as default};
